extension AnalyticsEvent {
    func log() {
        switch self {
        case .authenticationFlow(let userID):
            NSLog("Authentication Flow - User ID: \(userID)")
        case .apiCall(let endpoint, let method, let payload):
            if let payload = payload {
                NSLog("API Call - Endpoint: \(endpoint), Method: \(method.rawValue), Payload: \(payload)")
            } else {
                NSLog("API Call - Endpoint: \(endpoint), Method: \(method.rawValue)")
            }
        case .userDataChange(let userID, let changeType):
            NSLog("User Data Change - User ID: \(userID), Change Type: \(changeType)")
        case .error(let condition, let details):
            if let details = details {
